window.innerWidth < 768 && [].slice.call(document.querySelectorAll("[data-bss-disabled-mobile]")).forEach(function (element) {
  element.classList.remove("animated");
  element.removeAttribute("data-bss-hover-animate");
  element.removeAttribute("data-aos");
  element.removeAttribute("data-bss-parallax-bg");
  element.removeAttribute("data-bss-scroll-zoom");
});

document.addEventListener("DOMContentLoaded", function () {
  if ("AOS" in window) {
    AOS.init();
  }

  [].slice.call(document.querySelectorAll("[data-bss-hover-animate]")).forEach(function (element) {
    element.addEventListener("mouseenter", function (event) {
      event.target.classList.add("animated", event.target.dataset.bssHoverAnimate);
    });
    element.addEventListener("mouseleave", function (event) {
      event.target.classList.remove("animated", event.target.dataset.bssHoverAnimate);
    });
  });

  const swiperElements = document.querySelectorAll("[data-bss-swiper]");
  const navElements = document.querySelectorAll(".swiper-nav-standalone");
  if ("Swiper" in window) {
    for (const element of swiperElements) {
      const config = JSON.parse(element.dataset.bssSwiper);
      if (!config.navigation) {
        config.navigation = {};
        for (const navElement of navElements) {
          if (navElement.dataset.bssSwiperTarget === "#" + element.id) {
            config.navigation.prevEl = navElement.querySelector(".swiper-button-prev");
            config.navigation.nextEl = navElement.querySelector(".swiper-button-next");
            break;
          }
        }
      }
      new Swiper(element, config);
    }
  }
});

document.addEventListener("DOMContentLoaded", () => {
  const hero = document.querySelector("[data-hero-parallax]");
  if (!hero) {
    return;
  }

  const shapes = hero.querySelectorAll(".parallax-shape");
  const textBlocks = hero.querySelectorAll(".parallax-text");
  const image = hero.querySelector(".parallax-image");
  let ticking = false;

  const update = () => {
    const offset = hero.offsetTop;
    const height = hero.offsetHeight || 1;
    const progress = (window.scrollY - offset) / height;
    const clamped = Math.max(Math.min(progress, 1), -0.4);
    const range = Math.max(0.25 * Math.min(hero.offsetHeight || 400, Math.max(window.innerHeight, 400)), 60);

    shapes.forEach((shape) => {
      const speed = Number(shape.dataset.speed) || 0;
      const direction = Number(shape.dataset.direction) || 1;
      const translateY = clamped * range * speed * direction;
      shape.style.setProperty("--parallax-y", `${translateY.toFixed(2)}px`);
    });

    textBlocks.forEach((block, index) => {
      const factor = index === 0 ? 0.18 : 0.25;
      block.style.transform = `translateY(${(-clamped * range * factor).toFixed(1)}px)`;
      block.style.opacity = `${1 - 0.45 * Math.abs(clamped)}`;
    });

    if (image) {
      image.style.transform = `translateY(${(-clamped * range * 0.12).toFixed(1)}px) scale(${1 + 0.06 * Math.abs(clamped)})`;
    }

    ticking = false;
  };

  const requestUpdate = () => {
    if (!ticking) {
      ticking = true;
      requestAnimationFrame(update);
    }
  };

  window.addEventListener("scroll", requestUpdate, { passive: true });
  window.addEventListener("resize", requestUpdate);
  update();
});

const themePreferenceKey = "avanta-theme-preference";
const prefersDarkScheme = window.matchMedia("(prefers-color-scheme: dark)");
const themeLabelMap = { auto: "Auto", light: "Light", dark: "Dark" };
const themeIconClassMap = { light: "bi-sun-fill", dark: "bi-moon-stars-fill" };
const resolveTheme = (value) => value === "auto" ? prefersDarkScheme.matches ? "dark" : "light" : value;

document.addEventListener("DOMContentLoaded", () => {
  const button = document.getElementById("themeDropdownToggle");
  const options = document.querySelectorAll("[data-theme-value]");
  if (!button || options.length === 0) {
    return;
  }

  const icon = button.querySelector(".theme-toggle-icon");
  const label = button.querySelector(".visually-hidden");
  const getPreference = () => localStorage.getItem(themePreferenceKey) ?? "auto";
  const applyTheme = (preference) => {
    const resolved = resolveTheme(preference);
    document.documentElement.setAttribute("data-bs-theme", resolved);
    const activeLabel = themeLabelMap[preference] ?? "Auto";
    const activeIcon = themeIconClassMap[resolved] ?? "bi-sun-fill";
    if (icon) {
      icon.className = `theme-toggle-icon bi ${activeIcon} me-2`;
    }
    if (label) {
      label.textContent = `Theme: ${activeLabel}`;
    }
    button.setAttribute("aria-label", `Active theme: ${activeLabel}`);
    options.forEach((option) => {
      const isActive = option.dataset.themeValue === preference;
      option.classList.toggle("active", isActive);
      option.setAttribute("aria-checked", isActive ? "true" : "false");
    });
  };

  options.forEach((option) => {
    option.addEventListener("click", () => {
      const preference = option.dataset.themeValue;
      localStorage.setItem(themePreferenceKey, preference);
      applyTheme(preference);
    });
  });

  prefersDarkScheme.addEventListener("change", () => {
    if (getPreference() === "auto") {
      applyTheme("auto");
    }
  });

  applyTheme(getPreference());
});
